const segments = stage1.segments || {};
const anchor = meta.anchor || {};
const agentName = anchor.expected_agent_name || meta.agent_full_name || 'the agent';

const userMessage = 'HARD FACTS (regex-extracted, high confidence):\n' + JSON.stringify(meta.hard_facts, null, 2) + '\n\nANCHOR (caller-supplied hint):\n' + JSON.stringify(anchor, null, 2) + '\n\nAGENT TRANSCRIPT SEGMENTS:\n' + (segments.operational || '') + '\n\nExtract the following fields. Return null for any field not clearly stated.\n\n{"agent_full_name": "string | null","agent_first_name": "string | null","agent_last_name": "string | null","agent_title": "string | null","business_name": "string | null","agent_email": "string | null","agent_phone": "string | null","company_website": "string | null","funnel_url": "string | null","office_address": {"street": "string | null","city": "string | null","state": "string | null","zip": "string | null"},"market_area": "string | null","market_name": "string | null","timezone": "string | null","specialties_keywords": ["string"],"preferred_area_codes": ["string"],"coverage_cities": ["string"],"ai_coordinator_name": "string | null","agent_notes": "string | null","years_in_real_estate": "number | null","license_year": "number | null","confidence_notes": "string"}';

return [{
  json: {
    requestBody: JSON.stringify({
      model: 'gpt-4o-mini',
      temperature: 0.3,
      max_tokens: 2000,
      response_format: { type: 'json_object' },
      messages: [
        { role: 'system', content: `You are extracting structured operational data from a real estate agent onboarding interview.

RULES:
- Only extract facts explicitly stated by the AGENT (not the interviewer).
- If a field is not clearly stated, return null - do not guess.
- Confidence scale 1-10: only return fields with confidence >= 7.
- Hard facts (email, phone, zip) have been pre-extracted by regex - use those as ground truth if present.

Return ONLY valid JSON matching this exact schema. No commentary.` },
        { role: 'user', content: userMessage }
      ]
    }),
    meta: meta,
    segments: segments
  }
}];

