// ============================================================
// STAGE 3: MERGE + FLOOR CHECK
// Portrait Builder — SMRT Onboarding Pipeline
//
// Reads raw OpenAI HTTP responses from each Call node,
// parses choices[0].message.content, merges into one record.
// Flags short sections for review — does NOT fill with fake data.
// ============================================================

function safeParseJSON(str) {
  if (!str) return {};
  const cleaned = str.replace(/^```json\s*/i, '').replace(/\s*```$/i, '').trim();
  try {
    return JSON.parse(cleaned);
  } catch (e) {
    const jsonMatch = cleaned.match(/\{[\s\S]*\}/);
    if (jsonMatch) {
      try { return JSON.parse(jsonMatch[0]); } catch (e2) { return { _parse_error: str.substring(0, 200) }; }
    }
    return { _parse_error: str.substring(0, 200) };
  }
}

function parseOpenAIResponse(nodeName) {
  try {
    const item = $(nodeName).first().json;
    // n8n HTTP Request node returns the OpenAI API response directly
    const content = item.choices?.[0]?.message?.content
      || item.body?.choices?.[0]?.message?.content
      || '';
    if (!content) {
      return { _node_error: `Empty content from ${nodeName}` };
    }
    // Strip scratchpad lines before JSON (LLM sometimes adds "background: X chars | ...")
    const jsonStart = content.indexOf('{');
    const jsonStr = jsonStart >= 0 ? content.slice(jsonStart) : content;
    return safeParseJSON(jsonStr);
  } catch (e) {
    return { _node_error: `Could not read from ${nodeName}: ${e.message}` };
  }
}

// Pull and parse each extractor's raw OpenAI response
const callA = parseOpenAIResponse('Call A - Operational Fields');
const callB = parseOpenAIResponse('Call B - Origin and Geography');
const callC = parseOpenAIResponse('Call C - Method and Character');
const callD = parseOpenAIResponse('Call D - FAQ and Personal');

// Get Stage 1 meta
const stage1 = $('Stage 1 - Pre-processor').first().json;
const meta = stage1.meta || {};

// -- BIO SECTIONS (use empty string if missing — do NOT fill with placeholder text) ---
const bioSections = {
  background:   (typeof callB.background === 'string'   ? callB.background   : ''),
  areas_served: (typeof callB.areas_served === 'string' ? callB.areas_served : ''),
  specialties:  (typeof callC.specialties === 'string'  ? callC.specialties  : ''),
  style:        (typeof callC.style === 'string'        ? callC.style        : ''),
  faq:          (typeof callD.faq === 'string'          ? callD.faq          : '')
};

// -- FLOOR CHECK (flag only — never replace with fake content) ---
const FLOORS = {
  background:   800,
  areas_served: 800,
  specialties:  1000,
  style:        800,
